```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PresaleMint {
    address public owner;
    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;
    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;
    mapping(address => bool) internal _presalerList;

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    // Getters
    function isWhitelisted(address user) public view returns (bool) {
        return _presalerList[user];
    }

    function toggleSale() public onlyOwner {
        if (currentState == State.PresaleLive) {
            currentState = State.SaleLive;
        } else if (currentState == State.SaleLive) {
            currentState = State.SaleClosed;
        } else if (currentState == State.SaleClosed) {
            currentState = State.PresaleLive;
        }
    }

    function presaleBuy() public {
        require(currentState == State.PresaleLive, "Presale is not live");
        require(isWhitelisted(msg.sender), "Not whitelisted");
        presaleAmountMinted++;
    }

    function buy() public {
        require(currentState == State.SaleLive, "Sale is not live");
        publicAmountMinted++;
    }
}
```

